@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ChatScreen(
    contactName: String,
    receiverIdHex: String,
    viewModel: ChatViewModel,
    onBack: () -> Unit
) {
    val messages by viewModel.messages.collectAsState(initial = emptyList())
    var input by remember { mutableStateOf("") }
    val listState = rememberLazyListState()

    val keyboardController = LocalSoftwareKeyboardController.current
    val focusManager = LocalFocusManager.current

    var inputFocused by remember { mutableStateOf(false) }

    BackHandler {
        if (inputFocused) {
            keyboardController?.hide()
            focusManager.clearFocus(force = true)
        } else {
            onBack()
        }
    }

    // Hidden triple-tap gesture state
    var tapCount by remember { mutableIntStateOf(0) }
    var lastTapMs by remember { mutableLongStateOf(0L) }
    var showDeleteDialog by remember { mutableStateOf(false) }

    // Auto-scroll to the newest message whenever the list grows.
    LaunchedEffect(messages.size) {
        if (messages.isNotEmpty()) {
            runCatching { listState.animateScrollToItem(messages.lastIndex) }
        }
    }

    if (showDeleteDialog) {
        AlertDialog(
            onDismissRequest = { showDeleteDialog = false },
            title = { Text("Delete chat history?") },
            text = { Text("This cannot be undone.") },
            confirmButton = {
                TextButton(
                    onClick = {
                        showDeleteDialog = false
                        viewModel.deleteHistory(receiverIdHex)
                    }
                ) { Text("Confirm") }
            },
            dismissButton = {
                TextButton(onClick = { showDeleteDialog = false }) { Text("Cancel") }
            }
        )
    }

    // Track which messages existed on initial load so we only animate *new* ones.
    val seenMsgIds = remember { HashSet<String>() }
    var initialSnapshotDone by remember { mutableStateOf(false) }
    LaunchedEffect(messages.size) {
        if (!initialSnapshotDone) {
            messages.forEach { seenMsgIds.add(it.msgIdHex) }
            initialSnapshotDone = true
        }
    }

    Scaffold(
        topBar = {
            CenterAlignedTopAppBar(
                title = {
                    Text(
                        text = contactName,
                        modifier = Modifier.clickable {
                            val now = System.currentTimeMillis()
                            if (now - lastTapMs > 1000L) tapCount = 0
                            lastTapMs = now
                            tapCount += 1
                            if (tapCount >= 3) {
                                tapCount = 0
                                showDeleteDialog = true
                            }
                        }
                    )
                },
                navigationIcon = {
                    TextButton(onClick = onBack) { Text("Back") }
                }
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .imePadding() // keyboard pushes layout up
                .padding(12.dp)
        ) {
            Box(
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth()
            ) {
                LazyColumn(
                    modifier = Modifier.fillMaxSize(),
                    state = listState,
                    reverseLayout = false,
                    // Space ABOVE the first item so short chats are pinned to bottom.
                    verticalArrangement = Arrangement.Bottom,
                    contentPadding = PaddingValues(vertical = 8.dp)
                ) {
                    itemsIndexed(
                        items = messages,
                        key = { idx, msg -> "${msg.msgIdHex}-$idx" }
                    ) { _, msg ->
                        val animateOnFirstShow = initialSnapshotDone && !seenMsgIds.contains(msg.msgIdHex)
                        MessageBubble(message = msg, animateOnFirstShow = animateOnFirstShow)

                        LaunchedEffect(msg.msgIdHex) {
                            seenMsgIds.add(msg.msgIdHex)
                        }
                    }
                }
            }

            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically
            ) {
                OutlinedTextField(
                    value = input,
                    onValueChange = { input = it },
                    modifier = Modifier
                        .weight(1f)
                        .onFocusChanged { inputFocused = it.isFocused },
                    placeholder = { Text("Message") },
                    singleLine = true
                )
                Spacer(Modifier.width(8.dp))
                Button(
                    onClick = {
                        val text = input.trim()
                        if (text.isEmpty()) return@Button
                        input = ""
                        viewModel.sendMessage(text)
                    },
                    enabled = input.isNotBlank()
                ) {
                    Text("Send")
                }
            }
        }
    }
}

@Composable
private fun MessageBubble(
    message: ChatUiMessage,
    animateOnFirstShow: Boolean
) {
    val isMine = message.isMine
    val timeText = remember(message.timestampMs) {
        SimpleDateFormat("HH:mm", Locale.getDefault()).format(Date(message.timestampMs))
    }

    // Safe fade + subtle slide (no AnimatedVisibility / no animateItemPlacement)
    val alphaAnim = remember(message.msgIdHex) { Animatable(1f) }
    val offsetAnim = remember(message.msgIdHex) { Animatable(0f) }

    LaunchedEffect(message.msgIdHex, animateOnFirstShow) {
        if (animateOnFirstShow) {
            alphaAnim.snapTo(0f)
            offsetAnim.snapTo(-12f)
            alphaAnim.animateTo(
                1f,
                animationSpec = tween(durationMillis = 280, easing = FastOutSlowInEasing)
            )
            offsetAnim.animateTo(
                0f,
                animationSpec = tween(durationMillis = 280, easing = FastOutSlowInEasing)
            )
        } else {
            alphaAnim.snapTo(1f)
            offsetAnim.snapTo(0f)
        }
    }

    Row(
        modifier = Modifier
            .fillMaxWidth()
            .padding(vertical = 4.dp)
            .graphicsLayer {
                alpha = alphaAnim.value
                translationY = offsetAnim.value
            },
        horizontalArrangement = if (isMine) Arrangement.End else Arrangement.Start
    ) {
        Card(
            colors = CardDefaults.cardColors(
                containerColor = if (isMine) Color(0xFFE1FFC7) else Color(0xFFFFFFFF)
            ),
            modifier = Modifier.widthIn(max = 280.dp)
        ) {
            Column(modifier = Modifier.padding(10.dp)) {
                Text(message.text)
                Spacer(Modifier.height(6.dp))

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.End,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        text = timeText,
                        style = MaterialTheme.typography.labelSmall,
                        color = Color.Gray
                    )

                    if (isMine) {
                        Spacer(Modifier.width(6.dp))
                        when (message.status) {
                            DeliveryStatus.SENT -> {
                                Icon(
                                    Icons.Filled.Check,
                                    contentDescription = "Sent",
                                    tint = Color.Gray,
                                    modifier = Modifier.size(16.dp)
                                )
                            }

                            DeliveryStatus.DELIVERED -> {
                                Row {
                                    Icon(
                                        Icons.Filled.Check,
                                        contentDescription = "Delivered",
                                        tint = Color(0xFF009688),
                                        modifier = Modifier.size(16.dp)
                                    )
                                    Spacer(Modifier.width(2.dp))
                                    Icon(
                                        Icons.Filled.Check,
                                        contentDescription = "Delivered",
                                        tint = Color(0xFF009688),
                                        modifier = Modifier.size(16.dp)
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

package com.example.ble.ui

import android.content.Intent
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.automirrored.filled.ArrowBack
import androidx.compose.material.icons.filled.BugReport
import androidx.compose.material.icons.filled.Clear
import androidx.compose.material.icons.filled.Share
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.font.FontFamily
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.core.content.FileProvider
import com.example.ble.AppLogger
import java.io.File

@Composable
fun LogViewerScreen(
    onBack: () -> Unit
) {
    val context = LocalContext.current

    var query by remember { mutableStateOf("") }
    // A small tick to force refresh when screen is open (logs may be appended from threads).
    var refreshTick by remember { mutableIntStateOf(0) }

    LaunchedEffect(Unit) {
        while (true) {
            kotlinx.coroutines.delay(500)
            refreshTick++
        }
    }

    val entries = remember(refreshTick) { AppLogger.snapshot() }
    val filtered = remember(entries, query) {
        if (query.isBlank()) entries
        else entries.filter {
            it.tag.contains(query, ignoreCase = true) || it.message.contains(query, ignoreCase = true)
        }
    }

    fun shareLogsAsFile() {
        val text = AppLogger.dumpText(query)

        val senderId = extractSenderIdOrFallback(text)
        val firstTs = extractFirstTimestampOrNow(text)
        val safeTs = firstTs.replace(':', '-').replace('.', '-').replace(' ', '_')
        val fileName = "${senderId}_${safeTs}.txt"

        val file = File(context.cacheDir, fileName)
        file.writeText(text)

        val authority = "${context.packageName}.fileprovider"
        val uri = FileProvider.getUriForFile(context, authority, file)

        val intent = Intent(Intent.ACTION_SEND).apply {
            type = "text/plain"
            putExtra(Intent.EXTRA_STREAM, uri)
            addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
        }
        context.startActivity(Intent.createChooser(intent, "Share logs"))
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Logs") },
                navigationIcon = {
                    IconButton(onClick = onBack) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                    }
                },
                actions = {
                    IconButton(onClick = { AppLogger.clear(); refreshTick++ }) {
                        Icon(Icons.Filled.Clear, contentDescription = "Clear")
                    }
                    IconButton(onClick = { shareLogsAsFile() }) {
                        Icon(Icons.Filled.Share, contentDescription = "Share")
                    }
                }
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(12.dp),
            verticalArrangement = Arrangement.Top
        ) {
            OutlinedTextField(
                value = query,
                onValueChange = { query = it },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
                leadingIcon = { Icon(Icons.Filled.BugReport, contentDescription = null) },
                label = { Text("Filter by tag or message") }
            )

            Spacer(Modifier.height(8.dp))

            val newestFirst = filtered.asReversed()
            LazyColumn(
                modifier = Modifier.fillMaxSize(),
                contentPadding = PaddingValues(vertical = 4.dp)
            ) {
                items(
                    items = newestFirst,
                    key = { it.timestamp + it.tag + it.message.hashCode() }
                ) { e ->
                    val idx = newestFirst.indexOf(e)
                    val bg = if (idx % 2 == 0) MaterialTheme.colorScheme.surface else MaterialTheme.colorScheme.surfaceVariant
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(bg)
                            .padding(horizontal = 8.dp, vertical = 6.dp)
                    ) {
                        Text(
                            text = "${e.timestamp} ${e.level.name}/${e.tag}: ${e.message}",
                            fontFamily = FontFamily.Monospace,
                            fontSize = 11.sp,
                            color = Color.Unspecified
                        )
                    }
                }
            }
        }
    }
}

private fun extractFirstTimestampOrNow(text: String): String {
    // Expected line format: "HH:mm:ss.SSS ..."
    val firstLine = text.lineSequence().firstOrNull { it.isNotBlank() } ?: return "00:00:00.000"
    val ts = firstLine.takeWhile { it != ' ' }
    return if (ts.matches(Regex("\\d{2}:\\d{2}:\\d{2}\\.\\d{3}"))) ts else "00:00:00.000"
}

private fun extractSenderIdOrFallback(text: String): String {
    // We don’t have a guaranteed identity line in logs, so use best-effort:
    // Look for "senderId=" or "myId=" hex-ish tokens; fallback to "unknown".
    val regexes = listOf(
        Regex("senderId=([0-9a-fA-F]{8,})"),
        Regex("myId=([0-9a-fA-F]{8,})"),
        Regex("sender_id=([0-9a-fA-F]{8,})")
    )

    for (r in regexes) {
        val m = r.find(text)
        if (m != null) return m.groupValues[1]
    }

    return "unknown"
}

package com.example.ble.ui

import android.content.Intent
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.automirrored.filled.ArrowBack
import androidx.compose.material.icons.filled.BugReport
import androidx.compose.material.icons.filled.Clear
import androidx.compose.material.icons.filled.Share
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.font.FontFamily
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.core.content.FileProvider
import com.example.ble.AppLogger
import java.io.File

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun LogViewerScreen(
    onBack: () -> Unit
) {
    val context = LocalContext.current

    var query by remember { mutableStateOf("") }
    // A small tick to force refresh when screen is open (logs may be appended from threads).
    var refreshTick by remember { mutableIntStateOf(0) }

    LaunchedEffect(Unit) {
        while (true) {
            kotlinx.coroutines.delay(500)
            refreshTick++
        }
    }

    val entries = remember(refreshTick) { AppLogger.snapshot() }
    val filtered = remember(entries, query) {
        if (query.isBlank()) entries
        else entries.filter {
            it.tag.contains(query, ignoreCase = true) || it.message.contains(query, ignoreCase = true)
        }
    }

    fun shareLogsAsFile() {
        val text = AppLogger.dumpText(query)

        val senderId = extractSenderIdOrFallback(text)
        val firstTs = extractFirstTimestampOrNow(text)
        val safeTs = firstTs.replace(':', '-').replace('.', '-').replace(' ', '_')
        val fileName = "${senderId}_${safeTs}.txt"

        val file = File(context.cacheDir, fileName)
        file.writeText(text)

        val authority = "${context.packageName}.fileprovider"
        val uri = FileProvider.getUriForFile(context, authority, file)

        val intent = Intent(Intent.ACTION_SEND).apply {
            type = "text/plain"
            putExtra(Intent.EXTRA_STREAM, uri)
            addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
        }
        context.startActivity(Intent.createChooser(intent, "Share logs"))
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Logs") },
                navigationIcon = {
                    IconButton(onClick = onBack) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                    }
                },
                actions = {
                    IconButton(onClick = { AppLogger.clear(); refreshTick++ }) {
                        Icon(Icons.Filled.Clear, contentDescription = "Clear")
                    }
                    IconButton(onClick = { shareLogsAsFile() }) {
                        Icon(Icons.Filled.Share, contentDescription = "Share")
                    }
                }
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(12.dp),
            verticalArrangement = Arrangement.Top
        ) {
            OutlinedTextField(
                value = query,
                onValueChange = { query = it },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
                leadingIcon = { Icon(Icons.Filled.BugReport, contentDescription = null) },
                label = { Text("Filter by tag or message") }
            )

            Spacer(Modifier.height(8.dp))

            val newestFirst = filtered.asReversed()
            LazyColumn(
                modifier = Modifier.fillMaxSize(),
                contentPadding = PaddingValues(vertical = 4.dp)
            ) {
                items(
                    items = newestFirst,
                    key = { it.timestamp + it.tag + it.message.hashCode() }
                ) { e ->
                    val idx = newestFirst.indexOf(e)
                    val bg = if (idx % 2 == 0) MaterialTheme.colorScheme.surface else MaterialTheme.colorScheme.surfaceVariant
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(bg)
                            .padding(horizontal = 8.dp, vertical = 6.dp)
                    ) {
                        Text(
                            text = "${e.timestamp} ${e.level.name}/${e.tag}: ${e.message}",
                            fontFamily = FontFamily.Monospace,
                            fontSize = 11.sp,
                            color = Color.Unspecified
                        )
                    }
                }
            }
        }
    }
}

private fun extractFirstTimestampOrNow(text: String): String {
    // Expected line format: "HH:mm:ss.SSS ..."
    val firstLine = text.lineSequence().firstOrNull { it.isNotBlank() } ?: return "00:00:00.000"
    val ts = firstLine.takeWhile { it != ' ' }
    return if (ts.matches(Regex("\\d{2}:\\d{2}:\\d{2}\\.\\d{3}"))) ts else "00:00:00.000"
}

private fun extractSenderIdOrFallback(text: String): String {
    // We don’t have a guaranteed identity line in logs, so use best-effort:
    // Look for "senderId=" or "myId=" hex-ish tokens; fallback to "unknown".
    val regexes = listOf(
        Regex("senderId=([0-9a-fA-F]{8,})"),
        Regex("myId=([0-9a-fA-F]{8,})"),
        Regex("sender_id=([0-9a-fA-F]{8,})")
    )

    for (r in regexes) {
        val m = r.find(text)
        if (m != null) return m.groupValues[1]
    }

    return "unknown"
}
